import React, { useState, useEffect } from 'react';
import theaterService from '../services/theaterService';
import cityService from '../services/cityService';
import screenService from '../services/screenService';
import { useToast } from '../components/Toast';

export default function Theaters() {
  const [theaters, setTheaters] = useState([]);
  const [cities, setCities] = useState([]);
  const [activeCity, setActiveCity] = useState(null);
  const [loading, setLoading] = useState(true);
  const showToast = useToast();

  useEffect(() => {
    Promise.all([theaterService.getAll(), cityService.getAll()])
      .then(([t, c]) => { setTheaters(t); setCities(c); })
      .catch(() => showToast('Could not load data', 'error'))
      .finally(() => setLoading(false));
  }, []);

  const loadByCity = async (cityId) => {
    setActiveCity(cityId);
    setLoading(true);
    try {
      const data = cityId ? await theaterService.getByCity(cityId) : await theaterService.getAll();
      setTheaters(data);
    } catch {
      showToast('Could not load theaters', 'error');
    } finally {
      setLoading(false);
    }
  };

  const viewScreens = async (theaterId, theaterName) => {
    try {
      const screens = await screenService.getByTheater(theaterId);
      if (screens.length === 0) { showToast('No screens found', 'info'); return; }
      const msg = `${theaterName} Screens:\n` + screens.map(s => `• ${s.name} (${s.totalSeats || '?'} seats)`).join('\n');
      alert(msg);
    } catch {
      showToast('Could not load screens', 'error');
    }
  };

  return (
    <div className="container">
      <h2 className="section-title">Theaters</h2>

      {/* City Filter */}
      <div className="city-bar" style={{ background: 'transparent', padding: '0', marginBottom: '1.5rem', border: 'none' }}>
        <button className={`city-chip ${!activeCity ? 'active' : ''}`} onClick={() => loadByCity(null)}>All Cities</button>
        {cities.map(c => (
          <button key={c.id} className={`city-chip ${activeCity === c.id ? 'active' : ''}`} onClick={() => loadByCity(c.id)}>
            {c.name}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="loading-center"><div className="spinner"></div></div>
      ) : theaters.length === 0 ? (
        <div className="empty-state"><div className="icon">🏛️</div><p>No theaters found</p></div>
      ) : (
        <div className="grid grid-3">
          {theaters.map(t => (
            <div className="card" key={t.id}>
              <div className="card-body">
                <h3>🏛️ {t.name}</h3>
                <p>📍 {t.address || 'N/A'}</p>
                <p>🌆 {t.city?.name || ''}{t.city?.state ? `, ${t.city.state}` : ''}</p>
              </div>
              <div className="card-footer">
                <button className="btn btn-sm btn-outline" onClick={() => viewScreens(t.id, t.name)}>
                  View Screens
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
